# Layered OS Structure Simulation
# Each layer provides services to the layer above it

class Layer0Hardware:
    """Layer 0: Hardware - Physical devices"""
    def __init__(self):
        self.cpu_registers = {}
        self.memory_cells = [0] * 4096  # 4KB physical memory

    def read_memory(self, address):
        return self.memory_cells[address]

    def write_memory(self, address, value):
        self.memory_cells[address] = value

    def cpu_execute(self, instruction):
        return f"CPU executed: {instruction}"

class Layer1DeviceManagement:
    """Layer 1: Device Management - Handles I/O devices"""
    def __init__(self, hardware):
        self.hardware = hardware
        self.drivers = {}

    def register_driver(self, device_name, driver):
        self.drivers[device_name] = driver

    def read_from_device(self, device):
        if device in self.drivers:
            return self.drivers[device].read()
        return None

    def write_to_device(self, device, data):
        if device in self.drivers:
            return self.drivers[device].write(data)

class Layer2MemoryManagement:
    """Layer 2: Memory Management - Virtual memory, paging"""
    def __init__(self, device_layer):
        self.device_layer = device_layer
        self.page_table = {}
        self.physical_memory = [None] * 100

    def allocate_pages(self, process_id, num_pages):
        pages = []
        for i in range(num_pages):
            # Find free frame
            for frame in range(len(self.physical_memory)):
                if self.physical_memory[frame] is None:
                    self.physical_memory[frame] = process_id
                    pages.append(frame)
                    break
        self.page_table[process_id] = pages
        return pages

    def translate_address(self, virtual_addr, process_id):
        if process_id in self.page_table:
            page_num = virtual_addr // 1024
            offset = virtual_addr % 1024
            if page_num < len(self.page_table[process_id]):
                frame = self.page_table[process_id][page_num]
                return frame * 1024 + offset
        return -1

class Layer3ProcessManagement:
    """Layer 3: Process Management - Scheduling, IPC"""
    def __init__(self, memory_layer):
        self.memory_layer = memory_layer
        self.ready_queue = []
        self.blocked_queue = []

    def create_process(self, name, priority):
        pid = len(self.ready_queue) + len(self.blocked_queue) + 1
        process = {
            'pid': pid,
            'name': name,
            'priority': priority,
            'state': 'ready',
            'pages': self.memory_layer.allocate_pages(pid, 4)
        }
        self.ready_queue.append(process)
        return pid

    def schedule(self):
        if self.ready_queue:
            # Priority scheduling
            self.ready_queue.sort(key=lambda p: p['priority'])
            return self.ready_queue[0]
        return None

class Layer4FileSystem:
    """Layer 4: File System - Organized storage"""
    def __init__(self, process_layer):
        self.process_layer = process_layer
        self.file_table = {}
        self.directory_structure = {'/': {}}

    def create_file(self, path, content, pid):
        dirs = path.split('/')
        current = self.directory_structure['/']
        for d in dirs[1:-1]:
            if d not in current:
                current[d] = {}
            current = current[d]

        fd = len(self.file_table) + 1
        self.file_table[fd] = {'content': content, 'owner': pid, 'path': path}
        current[dirs[-1]] = fd
        return fd

    def read_file(self, fd):
        if fd in self.file_table:
            return self.file_table[fd]['content']
        return None

class Layer5UserInterface:
    """Layer 5: User Interface - System call interface"""
    def __init__(self, file_system):
        self.file_system = file_system

    def system_call(self, call_name, *args):
        calls = {
            'create_process': self.file_system.process_layer.create_process,
            'create_file': self.file_system.create_file,
            'read_file': self.file_system.read_file,
            'schedule': self.file_system.process_layer.schedule
        }
        return calls[call_name](*args)

# Demonstration of Layered Structure
print("=== Layered OS Structure ===\n")

# Build the layered system
hardware = Layer0Hardware()
device_layer = Layer1DeviceManagement(hardware)
memory_layer = Layer2MemoryManagement(device_layer)
process_layer = Layer3ProcessManagement(memory_layer)
file_system = Layer4FileSystem(process_layer)
user_interface = Layer5UserInterface(file_system)

# Use the layered system
print("Layer 5 (UI): Creating process...")
pid = user_interface.system_call('create_process', 'Editor', 2)
print(f"Process created with PID: {pid}")

print("\nLayer 5 (UI): Creating file...")
fd = user_interface.system_call('create_file', '/home/doc.txt', 'OS Notes', pid)
print(f"File descriptor: {fd}")

print("\nLayer 5 (UI): Reading file...")
content = user_interface.system_call('read_file', fd)
print(f"File content: {content}")

print("\nLayer 5 (UI): Scheduling...")
proc = user_interface.system_call('schedule')
print(f"Scheduled: {proc['name']} (Priority: {proc['priority']})")

# Microkernel Architecture Simulation
# Only essential services in kernel; others run as user-space servers

from enum import Enum

class ProcessState(Enum):
    READY = "ready"
    BLOCKED = "blocked"
    RUNNING = "running"

# ============ KERNEL SPACE (Minimal) ============

class MicroKernel:
    """Only essential functions run in kernel space"""

    def __init__(self):
        # Only kernel keeps track of these:
        self.process_control_block = {}
        self.message_queue = {}  # Inter-Process Communication
        self.interrupts = []
        self.memory_layout = {'kernel': [], 'user': []}

    def create_task(self, name, is_server=False):
        """Create a task (process) in kernel"""
        pid = len(self.process_control_block) + 1
        self.process_control_block[pid] = {
            'name': name,
            'state': ProcessState.READY,
            'is_server': is_server,
            'mailbox': []
        }
        return pid

    def send_message(self, from_pid, to_pid, message):
        """IPC - Message passing through kernel"""
        if to_pid in self.process_control_block:
            self.process_control_block[to_pid]['mailbox'].append({
                'from': from_pid,
                'message': message
            })
            # Unblock receiver if blocked
            if self.process_control_block[to_pid]['state'] == ProcessState.BLOCKED:
                self.process_control_block[to_pid]['state'] = ProcessState.READY
            return True
        return False

    def receive_message(self, pid):
        """Receive message from mailbox"""
        if pid in self.process_control_block:
            mailbox = self.process_control_block[pid]['mailbox']
            if mailbox:
                return mailbox.pop(0)
            else:
                # Block if no message
                self.process_control_block[pid]['state'] = ProcessState.BLOCKED
        return None

    def schedule(self):
        """Basic round-robin within kernel"""
        ready_processes = [p for p in self.process_control_block.values() 
                          if p['state'] == ProcessState.READY]
        if ready_processes:
            return ready_processes[0]
        return None

# ============ USER SPACE SERVERS ============

class FileSystemServer:
    """File system runs as user-space server process"""

    def __init__(self, kernel, server_pid):
        self.kernel = kernel
        self.server_pid = server_pid
        self.files = {}

    def handle_request(self, request):
        """Handle file operations via message"""
        if request['type'] == 'create':
            self.files[request['path']] = request['content']
            return {'status': 'ok', 'fd': len(self.files)}
        elif request['type'] == 'read':
            content = self.files.get(request['path'], 'Not found')
            return {'status': 'ok', 'content': content}
        return {'status': 'error'}

class NetworkServer:
    """Network services run as user-space server"""

    def __init__(self, kernel, server_pid):
        self.kernel = kernel
        self.server_pid = server_pid
        self.connections = {}

    def handle_request(self, request):
        """Handle network operations"""
        if request['type'] == 'connect':
            return {'status': 'connected', 'socket': 1}
        elif request['type'] == 'send':
            return {'status': 'sent'}
        return {'status': 'error'}

class DeviceDriverServer:
    """Device drivers run as user-space servers"""

    def __init__(self, kernel, server_pid):
        self.kernel = kernel
        self.server_pid = server_pid
        self.devices = {}

    def register_device(self, name):
        self.devices[name] = {'status': 'ready'}

    def handle_request(self, request):
        if request['type'] == 'read':
            return {'data': f"Data from {request['device']}"}
        return {'status': 'error'}

# ============ CLIENT APPLICATION ============

class Application:
    """User application interacts with servers via kernel"""

    def __init__(self, kernel, app_pid):
        self.kernel = kernel
        self.app_pid = app_pid

    def request_file(self, fs_server_pid, path, content=None):
        """Request file service via IPC"""
        if content:
            request = {'type': 'create', 'path': path, 'content': content}
        else:
            request = {'type': 'read', 'path': path}

        # Send message to file system server
        self.kernel.send_message(self.app_pid, fs_server_pid, request)

        # Wait for response (would block in real system)
        return fs_server_pid  # Return server to check response

# ============ DEMONSTRATION ============

print("=== Microkernel Architecture ===\n")

# Initialize microkernel
kernel = MicroKernel()

# Create servers as separate tasks (user space)
kernel_pid = 0  # Kernel itself
fs_server = kernel.create_task('FileSystemServer', is_server=True)
net_server = kernel.create_task('NetworkServer', is_server=True)
drv_server = kernel.create_task('DeviceDriverServer', is_server=True)
app = kernel.create_task('UserApplication', is_server=False)

print(f"Created File System Server (PID: {fs_server})")
print(f"Created Network Server (PID: {net_server})")
print(f"Created Device Driver Server (PID: {drv_server})")
print(f"Created User Application (PID: {app})")

# Initialize servers with kernel reference
fs_service = FileSystemServer(kernel, fs_server)
net_service = NetworkServer(kernel, net_server)
drv_service = DeviceDriverServer(kernel, drv_server)

print("\n--- Microkernel IPC Demo ---")

# User app requests file creation via message passing
app_obj = Application(kernel, app)
app_obj.request_file(fs_server, '/home/user/test.txt', 'Hello Microkernel!')

# Kernel processes message (simulated)
msg = kernel.receive_message(fs_server)
if msg:
    print(f"File System Server received: {msg['message']}")
    response = fs_service.handle_request(msg['message'])
    print(f"File System Server response: {response}")

    # Send response back to application
    kernel.send_message(fs_server, app, response)

# Check application mailbox
response = kernel.receive_message(app)
print(f"\nApplication received: {response}")

print("\n--- Key Microkernel Features ---")
print("✓ Only IPC, scheduling, basic memory in kernel space")
print("✓ File system, networking, drivers run as user processes")
print("✓ Message passing between components")
print("✓ Better fault isolation - driver crash doesn't crash kernel")
